+///
+/// Adding a type here REQUIRES verifying it is a pure identifier/tag, not
+/// authoritative content (PLAN §1.15 — coordination-not-authority).
+const CAD_CORE_ID_TAG_ALLOWLIST: &[&str] = &["BRepOwnerId", "BRepFaceId", "CuboidFaceTag"];
